import 'react-native-url-polyfill/auto';
import { createClient } from '@supabase/supabase-js';
import Constants from 'expo-constants';
import type { Database } from '@/types/supabase';
import { getCachedToken } from './storage';

type Extra = {
  SUPABASE_URL?: string;
  SUPABASE_ANON_KEY?: string;
};

const extra = (Constants.expoConfig?.extra ?? {}) as Extra;

if (!extra.SUPABASE_URL || !extra.SUPABASE_ANON_KEY) {
  throw new Error(
    'Missing SUPABASE_URL or SUPABASE_ANON_KEY. Populate .env and rebuild the Expo config.',
  );
}

// Inject our custom-issued Marketify JWT on every request. We read from the
// in-memory cache in `storage.ts` (AuthProvider keeps it in lock-step with
// SecureStore) so this stays synchronous. signIn / signOut mutate the cache
// and the next request picks it up — no client recreation needed.
const marketifyFetch: typeof fetch = (input, init) => {
  const token = getCachedToken();
  if (!token) {
    return fetch(input, init);
  }
  const headers = new Headers(init?.headers);
  headers.set('Authorization', `Bearer ${token}`);
  return fetch(input, { ...init, headers });
};

export const supabase = createClient<Database>(extra.SUPABASE_URL, extra.SUPABASE_ANON_KEY, {
  auth: {
    // We issue our own JWT via edge functions — disable Supabase Auth's
    // session handling so it doesn't fight the Authorization header above.
    persistSession: false,
    autoRefreshToken: false,
    detectSessionInUrl: false,
  },
  global: {
    fetch: marketifyFetch,
  },
});

import { Redirect, Slot } from 'expo-router';
import { Building2, Inbox, LayoutDashboard, Megaphone } from 'lucide-react-native';
import { StyleSheet, View } from 'react-native';
import { TabBar, type TabDef } from '@/components/shared/TabBar';
import { colors } from '@/design/tokens';
import { useAuth } from '@/lib/auth';

// Lister tab group — Home (index) / Campaigns / Inbox / Profile per US-031 AC
// + docs/design.md §3.2. Same custom-TabBar rationale as the creator layout:
// expo-router's native `<Tabs>` crashes in Expo Go + SDK 54 new-arch. The FAB
// is mounted on the Home screen per §3.2 ("Create-campaign is a FAB on
// Dashboard + Campaigns tabs — not a center-tab bump").
const LISTER_TABS: TabDef[] = [
  {
    label: 'Home',
    icon: LayoutDashboard,
    path: '/(lister)/dashboard',
    activePathname: '/dashboard',
    testID: 'tab-dashboard',
  },
  {
    label: 'Campaigns',
    icon: Megaphone,
    path: '/(lister)/campaigns',
    activePathname: '/campaigns',
    testID: 'tab-campaigns',
  },
  {
    label: 'Inbox',
    icon: Inbox,
    path: '/(lister)/inbox',
    activePathname: '/inbox',
    testID: 'tab-inbox',
  },
  {
    label: 'Profile',
    icon: Building2,
    path: '/(lister)/profile',
    activePathname: '/profile',
    testID: 'tab-profile',
  },
];

